// frontend/src/pages/Payments.js
import { useEffect, useMemo, useState } from "react";
import api from "../api";
import { useAuth } from "../AuthContext";

/* ===== Helpers ===== */
const VND = (v) => Number(v || 0).toLocaleString("vi-VN");
const todayStr = () => {
    const d = new Date();
    const m = String(d.getMonth() + 1).padStart(2, "0");
    const day = String(d.getDate()).padStart(2, "0");
    return `${d.getFullYear()}-${m}-${day}`;
};
const parseNumberText = (s) => Number(String(s ?? "").replace(/[^\d]/g, "") || 0);

const METHOD_OPTS = [
    { label: "Chuyển khoản", value: "BANK_TRANSFER" },
    { label: "Tiền mặt", value: "CASH" },
    { label: "Khác", value: "OTHER" },
];
const STATUS_OPTS = [
    { label: "Chưa thanh toán", value: "UNPAID" },
    { label: "Đã thanh toán", value: "PAID" },
];
const toLabel = (opts, v) =>
    opts.find((o) => o.value === v || o.label === v)?.label || v || "";
const toValue = (opts, l) =>
    opts.find((o) => o.label === l || o.value === l)?.value || l;

function hasAnyRole(user, allow = []) {
    if (!user) return false;
    const S = new Set();
    const add = (x) => {
        if (!x) return;
        if (Array.isArray(x)) return x.forEach(add);
        if (typeof x === "string") return S.add(x.toUpperCase());
        if (typeof x === "object")
            return ["role", "name", "authority"].forEach(
                (k) => x[k] && S.add(String(x[k]).toUpperCase())
            );
    };
    add(user?.role);
    add(user?.roles);
    add(user?.authorities);
    return allow.some((r) => S.has(r));
}

/* ===== Tiny toast ===== */
function Toast({ show, type = "success", children, onClose }) {
    if (!show) return null;
    const tone =
        type === "error"
            ? "bg-rose-600"
            : type === "warn"
                ? "bg-amber-600"
                : "bg-emerald-600";
    return (
        <div className="fixed top-4 right-4 z-[60]">
            <div className={`${tone} text-white px-4 py-2 rounded-lg shadow-lg`}>
                <div className="flex items-center gap-3">
                    <span className="text-sm">{children}</span>
                    <button
                        className="text-white/80 hover:text-white text-xs"
                        onClick={onClose}
                    >
                        Đóng
                    </button>
                </div>
            </div>
        </div>
    );
}

/* ===== Page ===== */
export default function Payments() {
    const { user } = useAuth();
    const canCreate = hasAnyRole(user, ["ADMIN", "SALES"]);
    const canMarkPaid = hasAnyRole(user, ["ADMIN", "ACCOUNTANT"]);
    const canDelete = hasAnyRole(user, ["ADMIN", "ACCOUNTANT"]);
    const canView = hasAnyRole(user, ["ADMIN", "ACCOUNTANT", "SALES"]);

    const [contracts, setContracts] = useState([]);
    const [rows, setRows] = useState([]); // payments of contract
    const [historyRows, setHistoryRows] = useState([]);
    const [activeTab, setActiveTab] = useState("payments"); // 'payments' | 'history'
    const [selectedContractId, setSelectedContractId] = useState("");
    const [loading, setLoading] = useState(true);
    const [loadingHistory, setLoadingHistory] = useState(false);

    // summary từ /payments/summary
    const [summary, setSummary] = useState(null);

    // Modal tạo đợt
    const [showCreate, setShowCreate] = useState(false);
    const [saving, setSaving] = useState(false);
    const [form, setForm] = useState({
        contractId: "",
        planDate: todayStr(),
        amount: "",
        method: "Chuyển khoản",
        note: "",
    });

    // Modal xác nhận đã thu
    const [showPaid, setShowPaid] = useState(false);
    const [paying, setPaying] = useState(false);
    const [activeRow, setActiveRow] = useState(null);
    const [paidForm, setPaidForm] = useState({
        amountText: "",
        paidDate: todayStr(),
        method: "Chuyển khoản",
        note: "",
    });

    // toast
    const [toast, setToast] = useState({ show: false, type: "success", msg: "" });
    const openToast = (msg, type = "success") =>
        setToast({ show: true, type, msg });
    const closeToast = () => setToast((t) => ({ ...t, show: false }));

    /* ---------- load contracts ---------- */
    useEffect(() => {
        (async () => {
            try {
                const { data } = await api.get("/api/contracts", {
                    params: { page: 0, size: 1000, sort: "id,desc" },
                });
                const list = Array.isArray(data) ? data : data?.content || [];
                setContracts(list);
                if (!selectedContractId && list[0]?.id) {
                    setSelectedContractId(String(list[0].id));
                }
            } catch (e) {
                console.error("Load contracts failed:", e);
            }
        })();
        // eslint-disable-next-line react-hooks/exhaustive-deps
    }, []);

    /* ---------- load by tab ---------- */
    useEffect(() => {
        if (!selectedContractId) {
            setRows([]);
            setHistoryRows([]);
            setSummary(null);
            return;
        }
        if (activeTab === "payments") {
            loadPaymentsSummary(selectedContractId);
        } else {
            loadHistoryByContract(selectedContractId);
        }
        // eslint-disable-next-line react-hooks/exhaustive-deps
    }, [selectedContractId, activeTab]);

    /* ---------- loaders ---------- */
    async function loadPaymentsSummary(contractId) {
        const id = Number(contractId);
        if (!id) {
            setRows([]);
            setSummary(null);
            return;
        }
        setLoading(true);
        try {
            // ✅ DÙNG TÓM TẮT + DS ĐỢT TỪ BACKEND
            const { data } = await api.get(`/api/contracts/${id}/payments/summary`);
            // data = { totalAmount, totalPaid, remaining, ... , payments: [] }
            setRows(Array.isArray(data?.payments) ? data.payments : []);
            setSummary({
                total: data?.totalAmount || 0,
                paid: data?.totalPaid || 0,
                remain:
                    data?.remaining ??
                    Math.max(0, (data?.totalAmount || 0) - (data?.totalPaid || 0)),
                code: data?.contractCode || data?.code || `HD-${id}`,
                customer: data?.customerName || "",
            });
        } catch (e) {
            console.error("loadPaymentsSummary error:", e?.response || e);
            openToast("Tải tổng hợp & đợt thanh toán thất bại", "error");
            setRows([]);
            setSummary(null);
        } finally {
            setLoading(false);
        }
    }

    async function loadHistoryByContract(contractId) {
        const id = Number(contractId);
        if (!id) return setHistoryRows([]);
        setLoadingHistory(true);
        try {
            const { data } = await api.get(`/api/contracts/${id}/payments/history`);
            setHistoryRows(Array.isArray(data) ? data : []);
        } catch (e) {
            console.error("loadHistory error:", e?.response || e);
            openToast("Tải lịch sử thanh toán thất bại", "error");
            setHistoryRows([]);
        } finally {
            setLoadingHistory(false);
        }
    }

    /* ---------- derived ---------- */
    const contractMap = useMemo(() => {
        const m = new Map();
        contracts.forEach((ct) => m.set(String(ct.id), ct));
        return m;
    }, [contracts]);

    const currentContract = selectedContractId
        ? contractMap.get(String(selectedContractId))
        : null;

    /* ---------- create installment ---------- */
    function openCreate() {
        const defaultContractId =
            selectedContractId || (contracts[0]?.id ? String(contracts[0].id) : "");
        setForm({
            contractId: defaultContractId,
            planDate: todayStr(),
            amount: "",
            method: "Chuyển khoản",
            note: "",
        });
        setShowCreate(true);
    }

    async function save(e) {
        e.preventDefault();
        const contractIdNum = Number(form.contractId);
        if (!contractIdNum) return openToast("Vui lòng chọn hợp đồng", "warn");

        const amountNum = parseNumberText(form.amount);
        if (!amountNum || amountNum <= 0)
            return openToast("Số tiền phải lớn hơn 0", "warn");

        const payload = {
            amount: amountNum,
            planDate: form.planDate || null,
            method: toValue(METHOD_OPTS, form.method),
            note: form.note?.trim() || null,
        };

        setSaving(true);
        try {
            await api.post(`/api/payments/by-contract/${contractIdNum}`, payload);
            setShowCreate(false);
            // reload summary + payments + (optional) history/contract
            await Promise.all([
                loadPaymentsSummary(contractIdNum),
                reloadContractsOnly(),
            ]);
            openToast("Tạo đợt thanh toán thành công");
            if (activeTab === "history") await loadHistoryByContract(contractIdNum);
        } catch (err) {
            const data = err?.response?.data;
            openToast(
                data?.message || data?.error || "Lưu thanh toán thất bại",
                "error"
            );
        } finally {
            setSaving(false);
        }
    }

    async function reloadContractsOnly() {
        try {
            const { data } = await api.get("/api/contracts", {
                params: { page: 0, size: 1000, sort: "id,desc" },
            });
            const list = Array.isArray(data) ? data : data?.content || [];
            setContracts(list);
        } catch (e) {
            console.error("Reload contracts failed:", e);
        }
    }

    async function removeRow(row) {
        if (!canDelete) return;
        const st = String(row.status || row.paymentStatus || "UNPAID").toUpperCase();
        if (st === "PAID") return openToast("Không xoá được đợt đã thanh toán", "warn");
        if (!window.confirm("Xoá đợt thanh toán này? (Chỉ xoá khi CHƯA THU)")) return;
        try {
            await api.delete(`/api/payments/${row.id}`);
            await Promise.all([
                loadPaymentsSummary(selectedContractId),
                reloadContractsOnly(),
            ]);
            openToast("Đã xoá đợt thanh toán");
            if (activeTab === "history") await loadHistoryByContract(selectedContractId);
        } catch (err) {
            openToast(
                err?.response?.data?.message || "Xoá thanh toán thất bại",
                "error"
            );
        }
    }

    /* ---------- mark paid (modal) ---------- */
    function openPaid(row) {
        setActiveRow(row);
        setPaidForm({
            amountText: VND(row.actualAmount ?? row.amount ?? 0),
            paidDate: todayStr(),
            method: "Chuyển khoản",
            note: "",
        });
        setShowPaid(true);
    }

    async function doMarkPaid(e) {
        e.preventDefault();
        if (!activeRow?.id) return;
        setPaying(true);
        try {
            const actual = parseNumberText(paidForm.amountText);

            await api.patch(`/api/payments/${activeRow.id}/mark-paid`, null, {
                params: {
                    paidDate: paidForm.paidDate || todayStr(),
                    method: toValue(METHOD_OPTS, paidForm.method),
                    note: paidForm.note?.trim() || null,
                    actualAmount: actual || null,
                },
            });
            setShowPaid(false);
            await Promise.all([
                loadPaymentsSummary(selectedContractId),
                reloadContractsOnly(),
            ]);
            openToast("Đã cập nhật trạng thái: Đã thanh toán");
            if (activeTab === "history") await loadHistoryByContract(selectedContractId);
        } catch (err) {
            const data = err?.response?.data;
            openToast(
                data?.message || data?.error || "Cập nhật trạng thái 'Đã thanh toán' thất bại",
                "error"
            );
        } finally {
            setPaying(false);
        }
    }

    /* ---------- render ---------- */
    if (!canView) {
        return (
            <div className="space-y-3">
                <h2 className="text-lg font-semibold">Thanh toán</h2>
                <p className="text-sm text-slate-500">Bạn không có quyền xem trang này.</p>
            </div>
        );
    }

    return (
        <div className="space-y-5">
            <Toast show={toast.show} type={toast.type} onClose={closeToast}>
                {toast.msg}
            </Toast>

            {/* Header */}
            <div className="flex items-center justify-between gap-3">
                <div>
                    <h2 className="text-lg font-semibold">Thanh toán</h2>
                    <p className="text-sm text-slate-500">
                        Quản lý các đợt thanh toán theo hợp đồng
                    </p>
                </div>

                <div className="flex items-center gap-3">
                    <select
                        value={selectedContractId}
                        onChange={(e) => setSelectedContractId(e.target.value)}
                        className="px-3 py-2 rounded-xl border border-indigo-100 bg-white shadow min-w-[280px]"
                        title="Chọn hợp đồng"
                    >
                        {contracts.map((ct) => {
                            const code = ct.contractCode || ct.code || `HD-${ct.id}`;
                            const cus = ct.customer?.name || ct.customerName || "";
                            return (
                                <option key={ct.id} value={ct.id}>
                                    {code} - {cus}
                                </option>
                            );
                        })}
                    </select>

                    {canCreate && (
                        <button
                            onClick={openCreate}
                            className="px-3 py-2 rounded-xl bg-indigo-600 text-white hover:bg-indigo-700 disabled:opacity-50"
                            disabled={!contracts?.length}
                            title={!contracts?.length ? "Chưa có hợp đồng để tạo đợt" : undefined}
                        >
                            Thêm đợt thanh toán
                        </button>
                    )}
                </div>
            </div>

            {/* Tabs */}
            <div className="flex items-center gap-4 border-b">
                <button
                    className={`pb-2 ${
                        activeTab === "payments"
                            ? "border-b-2 border-indigo-600 font-medium"
                            : "text-slate-500"
                    }`}
                    onClick={() => setActiveTab("payments")}
                >
                    Đợt thanh toán
                </button>
                <button
                    className={`pb-2 ${
                        activeTab === "history"
                            ? "border-b-2 border-indigo-600 font-medium"
                            : "text-slate-500"
                    }`}
                    onClick={() => setActiveTab("history")}
                >
                    Lịch sử thanh toán
                </button>
            </div>

            {/* Summary */}
            {summary && (
                <div className="grid grid-cols-1 sm:grid-cols-3 gap-3">
                    <div className="rounded-2xl bg-white border border-indigo-100 shadow p-4">
                        <div className="text-xs text-slate-500">Tổng giá trị</div>
                        <div className="text-lg font-semibold tabular-nums">
                            {VND(summary.total)} đ
                        </div>
                    </div>
                    <div className="rounded-2xl bg-white border border-indigo-100 shadow p-4">
                        <div className="text-xs text-slate-500">Đã thu</div>
                        <div className="text-lg font-semibold tabular-nums">
                            {VND(summary.paid)} đ
                        </div>
                    </div>
                    <div className="rounded-2xl bg-white border border-indigo-100 shadow p-4">
                        <div className="text-xs text-slate-500">Còn lại</div>
                        <div className="text-lg font-semibold tabular-nums">
                            {VND(summary.remain)} đ
                        </div>
                    </div>
                </div>
            )}

            {/* Table: ĐỢT THANH TOÁN */}
            {activeTab === "payments" && (
                <div className="bg-white rounded-2xl border border-indigo-100 shadow overflow-hidden">
                    <div className="overflow-auto">
                        <table className="min-w-full text-sm">
                            <thead className="bg-indigo-50 text-slate-600">
                            <tr>
                                <th className="px-4 py-3 text-left">Mã HĐ</th>
                                <th className="px-4 py-3 text-left">Ngày trả / dự kiến</th>
                                <th className="px-4 py-3 text-left">Số tiền</th>
                                <th className="px-4 py-3 text-left">Phương thức</th>
                                <th className="px-4 py-3 text-left">Trạng thái</th>
                                <th className="px-4 py-3 text-left">Người xác nhận</th>
                                <th className="px-4 py-3 text-left">Ghi chú</th>
                                <th className="px-4 py-3 text-right">Thao tác</th>
                            </tr>
                            </thead>
                            <tbody className="divide-y">
                            {loading ? (
                                <tr>
                                    <td className="px-4 py-6" colSpan={8}>
                                        Đang tải…
                                    </td>
                                </tr>
                            ) : rows.length === 0 ? (
                                <tr>
                                    <td className="px-4 py-6" colSpan={8}>
                                        Chưa có dữ liệu
                                    </td>
                                </tr>
                            ) : (
                                rows.map((p) => {
                                    const code =
                                        p.contractCode ||
                                        p.contract?.contractCode ||
                                        p.contract?.code ||
                                        (p.contractId ? "HD-" + p.contractId : "");
                                    const method = p.method || p.paymentMethod;
                                    const mLabel = toLabel(METHOD_OPTS, method);
                                    const statusValue = String(
                                        p.status || p.paymentStatus || "UNPAID"
                                    ).toUpperCase();
                                    const sLabel = toLabel(STATUS_OPTS, statusValue);
                                    const isPaid = statusValue === "PAID";
                                    const dateDisplay = p.paymentDate ?? p.planDate ?? "-";
                                    const confirmer = p.confirmedByName || p.confirmedBy || "-";

                                    return (
                                        <tr key={p.id} className="hover:bg-indigo-50/40">
                                            <td className="px-4 py-3 font-medium">{code}</td>
                                            <td className="px-4 py-3">{dateDisplay}</td>
                                            <td className="px-4 py-3 tabular-nums">
                                                {VND(p.amount ?? 0)} đ
                                            </td>
                                            <td className="px-4 py-3">{mLabel || "-"}</td>
                                            <td className="px-4 py-3">
                          <span
                              className={
                                  "px-2 py-0.5 rounded-full text-xs " +
                                  (isPaid
                                      ? "bg-emerald-100 text-emerald-700"
                                      : "bg-amber-100 text-amber-700")
                              }
                          >
                            {sLabel || "-"}
                          </span>
                                            </td>
                                            <td className="px-4 py-3">{confirmer}</td>
                                            <td className="px-4 py-3">{p.note || "-"}</td>
                                            <td className="px-4 py-3 text-right">
                                                <div className="inline-flex gap-2">
                                                    {!isPaid && canMarkPaid && (
                                                        <button
                                                            onClick={() => openPaid(p)}
                                                            className="px-2 py-1 rounded bg-emerald-50 text-emerald-700 hover:bg-emerald-100"
                                                            title="Xác nhận đã thanh toán"
                                                        >
                                                            Xác nhận đã thu
                                                        </button>
                                                    )}
                                                    {!isPaid && canDelete && (
                                                        <button
                                                            onClick={() => removeRow(p)}
                                                            className="px-2 py-1 rounded bg-rose-50 text-rose-700 hover:bg-rose-100"
                                                            title="Xóa đợt thanh toán (chỉ khi CHƯA THU)"
                                                        >
                                                            Xóa
                                                        </button>
                                                    )}
                                                    {isPaid && <span className="text-slate-400">—</span>}
                                                </div>
                                            </td>
                                        </tr>
                                    );
                                })
                            )}
                            </tbody>
                        </table>
                    </div>
                </div>
            )}

            {/* Table: LỊCH SỬ THANH TOÁN */}
            {activeTab === "history" && (
                <div className="bg-white rounded-2xl border border-indigo-100 shadow overflow-hidden">
                    <div className="overflow-auto">
                        <table className="min-w-full text-sm">
                            <thead className="bg-indigo-50 text-slate-600">
                            <tr>
                                <th className="px-4 py-3 text-left">Thời điểm</th>
                                <th className="px-4 py-3 text-left">Hành động</th>
                                <th className="px-4 py-3 text-left">Đợt</th>
                                <th className="px-4 py-3 text-left">Trước → Sau</th>
                                <th className="px-4 py-3 text-left">Thực thu</th>
                                <th className="px-4 py-3 text-left">Trạng thái</th>
                                <th className="px-4 py-3 text-left">Phương thức</th>
                                <th className="px-4 py-3 text-left">Người thực hiện</th>
                                <th className="px-4 py-3 text-left">Ghi chú</th>
                            </tr>
                            </thead>
                            <tbody className="divide-y">
                            {loadingHistory ? (
                                <tr>
                                    <td className="px-4 py-6" colSpan={9}>
                                        Đang tải…
                                    </td>
                                </tr>
                            ) : historyRows.length === 0 ? (
                                <tr>
                                    <td className="px-4 py-6" colSpan={9}>
                                        Chưa có lịch sử
                                    </td>
                                </tr>
                            ) : (
                                historyRows.map((h) => (
                                    <tr key={h.id} className="hover:bg-indigo-50/40">
                                        <td className="px-4 py-3">
                                            {h.createdAt
                                                ? new Date(h.createdAt).toLocaleString("vi-VN")
                                                : "-"}
                                        </td>
                                        <td className="px-4 py-3">{h.action}</td>
                                        <td className="px-4 py-3">{h.paymentId || "-"}</td>
                                        <td className="px-4 py-3 tabular-nums">
                                            {VND(h.amountBefore || 0)} → {VND(h.amountAfter || 0)}
                                        </td>
                                        <td className="px-4 py-3 tabular-nums">
                                            {h.actualAmount != null ? `${VND(h.actualAmount)} đ` : "-"}
                                        </td>
                                        <td className="px-4 py-3">
                                            {(h.statusBefore || "-") + " → " + (h.statusAfter || "-")}
                                        </td>
                                        <td className="px-4 py-3">
                                            {toLabel(METHOD_OPTS, h.method) || "-"}
                                        </td>
                                        <td className="px-4 py-3">{h.actor || "-"}</td>
                                        <td className="px-4 py-3">{h.note || "-"}</td>
                                    </tr>
                                ))
                            )}
                            </tbody>
                        </table>
                    </div>
                </div>
            )}

            {/* Modal tạo đợt */}
            {showCreate && canCreate && (
                <div className="fixed inset-0 z-40 bg-black/40 grid place-items-center p-4">
                    <div className="w-full max-w-3xl bg-white rounded-2xl shadow-xl border border-indigo-100">
                        <div className="p-5 border-b flex items-center justify-between">
                            <div className="font-semibold">Thêm đợt thanh toán</div>
                            <button
                                className="text-slate-500 hover:text-slate-700"
                                onClick={() => setShowCreate(false)}
                            >
                                Đóng
                            </button>
                        </div>

                        <form onSubmit={save} className="p-5 grid grid-cols-1 md:grid-cols-2 gap-4">
                            <div className="md:col-span-2">
                                <label className="text-sm text-slate-600">Hợp đồng</label>
                                <select
                                    required
                                    value={form.contractId}
                                    onChange={(e) =>
                                        setForm((f) => ({ ...f, contractId: e.target.value }))
                                    }
                                    className="w-full px-3 py-2 rounded-lg border border-indigo-100 bg-white shadow"
                                >
                                    {contracts.map((ct) => {
                                        const code = ct.contractCode || ct.code || `HD-${ct.id}`;
                                        const cus = ct.customer?.name || ct.customerName || "";
                                        return (
                                            <option key={ct.id} value={ct.id}>
                                                {code} - {cus}
                                            </option>
                                        );
                                    })}
                                </select>
                            </div>

                            <div>
                                <label className="text-sm text-slate-600">Ngày dự kiến thu</label>
                                <input
                                    type="date"
                                    value={form.planDate}
                                    onChange={(e) =>
                                        setForm((f) => ({ ...f, planDate: e.target.value }))
                                    }
                                    className="w-full px-3 py-2 rounded-lg border border-indigo-100 bg-white shadow"
                                />
                            </div>

                            <div>
                                <label className="text-sm text-slate-600">Số tiền (đ)</label>
                                <input
                                    required
                                    type="text"
                                    inputMode="numeric"
                                    pattern="[0-9\.]*"
                                    placeholder="VD: 200.000.000"
                                    value={form.amount}
                                    onChange={(e) =>
                                        setForm((f) => ({
                                            ...f,
                                            amount: e.target.value
                                                .replace(/[^\d]/g, "")
                                                .replace(/\B(?=(\d{3})+(?!\d))/g, "."),
                                        }))
                                    }
                                    className="w-full px-3 py-2 rounded-lg border border-indigo-100 bg-white shadow tabular-nums"
                                />
                            </div>

                            <div>
                                <label className="text-sm text-slate-600">Phương thức</label>
                                <select
                                    value={form.method}
                                    onChange={(e) => setForm((f) => ({ ...f, method: e.target.value }))}
                                    className="w-full px-3 py-2 rounded-lg border border-indigo-100 bg-white shadow"
                                >
                                    {METHOD_OPTS.map((o) => (
                                        <option key={o.value} value={o.label}>
                                            {o.label}
                                        </option>
                                    ))}
                                </select>
                            </div>

                            <div className="md:col-span-2">
                                <label className="text-sm text-slate-600">Ghi chú</label>
                                <input
                                    placeholder="VD: Thu đợt 1"
                                    value={form.note}
                                    onChange={(e) => setForm((f) => ({ ...f, note: e.target.value }))}
                                    className="w-full px-3 py-2 rounded-lg border border-indigo-100 bg-white shadow"
                                />
                            </div>

                            <div className="md:col-span-2 flex items-center justify-end gap-2 pt-2">
                                <button
                                    type="button"
                                    className="px-3 py-2 rounded-lg bg-slate-100 hover:bg-slate-200"
                                    onClick={() => setShowCreate(false)}
                                    disabled={saving}
                                >
                                    Hủy
                                </button>
                                <button
                                    className="px-3 py-2 rounded-lg bg-indigo-600 text-white hover:bg-indigo-700 disabled:opacity-50"
                                    disabled={saving}
                                >
                                    {saving ? "Đang lưu..." : "Lưu"}
                                </button>
                            </div>
                        </form>
                    </div>
                </div>
            )}

            {/* Modal xác nhận đã thu */}
            {showPaid && activeRow && (
                <div className="fixed inset-0 z-50 bg-black/40 grid place-items-center p-4">
                    <div className="w-full max-w-lg bg-white rounded-2xl shadow-xl border border-indigo-100">
                        <div className="p-5 border-b flex items-center justify-between">
                            <div className="font-semibold">Xác nhận đã thu</div>
                            <button
                                className="text-slate-500 hover:text-slate-700"
                                onClick={() => setShowPaid(false)}
                            >
                                Đóng
                            </button>
                        </div>

                        <form onSubmit={doMarkPaid} className="p-5 space-y-3">
                            <div>
                                <label className="text-sm text-slate-600">Số tiền THỰC THU (đ)</label>
                                <input
                                    value={paidForm.amountText}
                                    readOnly
                                    className="w-full px-3 py-2 rounded-lg border border-indigo-100 bg-slate-50 shadow tabular-nums"
                                />
                                <div className="text-xs text-slate-500 mt-1">
                                    * Hệ thống sẽ ghi nhận số tiền hiển thị này làm thực thu (không cần nhập).
                                </div>
                            </div>

                            <div>
                                <label className="text-sm text-slate-600">Ngày thu</label>
                                <input
                                    type="date"
                                    value={paidForm.paidDate}
                                    onChange={(e) =>
                                        setPaidForm((f) => ({ ...f, paidDate: e.target.value }))
                                    }
                                    className="w-full px-3 py-2 rounded-lg border border-indigo-100 bg-white shadow"
                                />
                            </div>

                            <div>
                                <label className="text-sm text-slate-600">Phương thức</label>
                                <select
                                    value={paidForm.method}
                                    onChange={(e) =>
                                        setPaidForm((f) => ({ ...f, method: e.target.value }))
                                    }
                                    className="w-full px-3 py-2 rounded-lg border border-indigo-100 bg-white shadow"
                                >
                                    {METHOD_OPTS.map((o) => (
                                        <option key={o.value} value={o.label}>
                                            {o.label}
                                        </option>
                                    ))}
                                </select>
                            </div>

                            <div>
                                <label className="text-sm text-slate-600">Ghi chú</label>
                                <input
                                    placeholder="VD: Thu đủ đợt 2"
                                    value={paidForm.note}
                                    onChange={(e) =>
                                        setPaidForm((f) => ({ ...f, note: e.target.value }))
                                    }
                                    className="w-full px-3 py-2 rounded-lg border border-indigo-100 bg-white shadow"
                                />
                            </div>

                            <div className="flex items-center justify-end gap-2 pt-1">
                                <button
                                    type="button"
                                    className="px-3 py-2 rounded-lg bg-slate-100 hover:bg-slate-200"
                                    onClick={() => setShowPaid(false)}
                                    disabled={paying}
                                >
                                    Hủy
                                </button>
                                <button
                                    className="px-3 py-2 rounded-lg bg-emerald-600 text-white hover:bg-emerald-700 disabled:opacity-50"
                                    disabled={paying}
                                >
                                    {paying ? "Đang cập nhật..." : "Xác nhận đã thu"}
                                </button>
                            </div>
                        </form>
                    </div>
                </div>
            )}
        </div>
    );
}
